@namespace Lumeo
@using Lumeo.Services
@using Blazicons
@implements IDisposable
@inject ThemeService Theme
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<div class="@CssClass" @attributes="AdditionalAttributes">
    <!-- Color scheme swatches -->
    <div>
        <p class="mb-2 text-xs font-medium text-muted-foreground">@L["Theme.Color"]</p>
        <div class="flex flex-wrap gap-2">
            @foreach (var scheme in ThemeService.AvailableSchemes)
            {
                <button class="@GetSwatchClass(scheme.Id)"
                        style="background-color: @scheme.PreviewColor;"
                        title="@scheme.DisplayName"
                        @onclick="() => SetScheme(scheme.Id)">
                    @if (scheme.Id == _currentScheme)
                    {
                        <Blazicon Svg="Lucide.Check" class="h-3 w-3 text-white" />
                    }
                </button>
            }
        </div>
    </div>

    <!-- Mode toggle -->
    <div>
        <p class="mb-2 text-xs font-medium text-muted-foreground">@L["Theme.Mode"]</p>
        <div class="inline-flex items-center gap-1 rounded-lg border border-border/50 bg-muted p-1">
            <button class="@GetModeButtonClass(ThemeMode.Light)"
                    title="@L["Theme.Light"]"
                    @onclick="() => SetMode(ThemeMode.Light)">
                <Blazicon Svg="Lucide.Sun" class="h-3.5 w-3.5" />
            </button>
            <button class="@GetModeButtonClass(ThemeMode.Dark)"
                    title="@L["Theme.Dark"]"
                    @onclick="() => SetMode(ThemeMode.Dark)">
                <Blazicon Svg="Lucide.Moon" class="h-3.5 w-3.5" />
            </button>
            <button class="@GetModeButtonClass(ThemeMode.System)"
                    title="@L["Theme.System"]"
                    @onclick="() => SetMode(ThemeMode.System)">
                <Blazicon Svg="Lucide.Monitor" class="h-3.5 w-3.5" />
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Bug F — these are overwritten in OnInitializedAsync; the field initializers are intentionally
    // neutral placeholders. OnInitializedAsync reads the real values from ThemeService before the
    // first render, so the UI is correct from the very first paint (no stale-default flash).
    private string _currentScheme = "zinc";
    private ThemeMode _currentMode = ThemeMode.System;

    private string CssClass => Cx.Merge("space-y-4", Class);

    protected override async Task OnInitializedAsync()
    {
        // Read scheme and mode synchronously from ThemeService before first render.
        // ThemeService.CurrentScheme / CurrentMode are populated during DI startup
        // or by a prior InitializeAsync call; reading them here avoids a stale first paint.
        _currentScheme = Theme.CurrentScheme;
        _currentMode = Theme.CurrentMode;
        Theme.OnThemeChanged += OnThemeChanged;
        await base.OnInitializedAsync();
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            // JS interop must run after render; re-sync in case the JS-side state
            // differs from the server-side defaults (e.g. persisted user preference).
            await Theme.InitializeAsync();
            _currentScheme = Theme.CurrentScheme;
            _currentMode = Theme.CurrentMode;
            StateHasChanged();
        }
    }

    private async Task SetScheme(string scheme)
    {
        _currentScheme = scheme;
        await Theme.SetSchemeAsync(scheme);
    }

    private async Task SetMode(ThemeMode mode)
    {
        _currentMode = mode;
        await Theme.SetModeAsync(mode);
    }

    private void OnThemeChanged()
    {
        _currentScheme = Theme.CurrentScheme;
        _currentMode = Theme.CurrentMode;
        InvokeAsync(StateHasChanged);
    }

    private string GetSwatchClass(string schemeId)
    {
        var baseClass = "flex h-8 w-8 items-center justify-center rounded-full border border-primary transition-all focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2";
        return schemeId == _currentScheme
            ? $"{baseClass} border-foreground scale-110"
            : $"{baseClass} border-transparent hover:scale-105";
    }

    private string GetModeButtonClass(ThemeMode mode)
    {
        var baseClass = "inline-flex items-center justify-center rounded-md px-2.5 py-1.5 text-sm transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1";
        return mode == _currentMode
            ? $"{baseClass} bg-background text-foreground shadow-sm"
            : $"{baseClass} text-muted-foreground hover:text-foreground";
    }

    public void Dispose()
    {
        Theme.OnThemeChanged -= OnThemeChanged;
    }
}
